import axios from 'axios';
import config from '../config/api';

const apiService = {
    // Authentication APIs
    
    register: async (name, email, password) => {
        const formData = new FormData();
        formData.append("name", name);
        formData.append("email", email);
        formData.append("password", password);
        const response = await axios.post(
            `${config.API_URL}${config.ENDPOINTS.REGISTER}`,
            formData,
            {
                headers: { "Content-Type": "multipart/form-data" }
            }
        );
        return response.data;
    },

    login: async (email, password) => {
        const formData = new FormData();
        formData.append("email", email);
        formData.append("password", password);
        const response = await axios.post(
            `${config.API_URL}${config.ENDPOINTS.LOGIN}`,
            formData,
            {
                headers: { "Content-Type": "multipart/form-data" }
            }
        );
        return response.data;
    },

    getUser: async (userId) => {
        const response = await axios.get(`${config.API_URL}${config.ENDPOINTS.GET_USER}${userId}`);
        return response.data;
    },

    // Basic functionality
    
    // Transcription service
    transcribeAudio: async (audioBlob) => {
        const formData = new FormData();
        formData.append("file", audioBlob, "audio.wav");
        const response = await axios.post(
            `${config.API_URL}${config.ENDPOINTS.TRANSCRIBE}`,
            formData,
            {
                headers: { "Content-Type": "multipart/form-data" }
            }
        );
        return response.data;
    },

    // Code generation service
    generateCode: async (problem, language) => {
        const formData = new FormData();
        formData.append("problem", problem);
        formData.append("language", language);
        const response = await axios.post(
            `${config.API_URL}${config.ENDPOINTS.GENERATE_CODE}`,
            formData,
            {
                headers: { "Content-Type": "multipart/form-data" }
            }
        );
        return response.data;
    },

    // Code compilation service
    compileCode: async (code, language, inputs) => {
        const formData = new FormData();
        formData.append("code", code);
        formData.append("language", language);
        formData.append("inputs", inputs);
        const response = await axios.post(
            `${config.API_URL}${config.ENDPOINTS.COMPILE}`,
            formData,
            {
                headers: { "Content-Type": "multipart/form-data" }
            }
        );
        return response.data;
    },

    // Learning Mode APIs
    
    explainCode: async (code, language, difficultyLevel = 'beginner') => {
        const formData = new FormData();
        formData.append("code", code);
        formData.append("language", language);
        formData.append("difficulty_level", difficultyLevel);
        const response = await axios.post(
            `${config.API_URL}${config.ENDPOINTS.EXPLAIN_CODE}`,
            formData,
            {
                headers: { "Content-Type": "multipart/form-data" }
            }
        );
        return response.data;
    },

    analyzeError: async (code, language, errorMessage) => {
        const formData = new FormData();
        formData.append("code", code);
        formData.append("language", language);
        formData.append("error_message", errorMessage);
        const response = await axios.post(
            `${config.API_URL}${config.ENDPOINTS.ANALYZE_ERROR}`,
            formData,
            {
                headers: { "Content-Type": "multipart/form-data" }
            }
        );
        return response.data;
    },

    // Collaboration APIs
    
    createCollaborationSession: async (sessionName, creatorId) => {
        const formData = new FormData();
        formData.append("session_name", sessionName);
        formData.append("creator_id", creatorId);
        const response = await axios.post(
            `${config.API_URL}${config.ENDPOINTS.CREATE_SESSION}`,
            formData,
            {
                headers: { "Content-Type": "multipart/form-data" }
            }
        );
        return response.data;
    },

    joinCollaborationSession: async (sessionId, userId) => {
        const formData = new FormData();
        formData.append("session_id", sessionId);
        formData.append("user_id", userId);
        const response = await axios.post(
            `${config.API_URL}${config.ENDPOINTS.JOIN_SESSION}`,
            formData,
            {
                headers: { "Content-Type": "multipart/form-data" }
            }
        );
        return response.data;
    },

    leaveCollaborationSession: async (sessionId, userId) => {
        const formData = new FormData();
        formData.append("session_id", sessionId);
        formData.append("user_id", userId);
        const response = await axios.post(
            `${config.API_URL}${config.ENDPOINTS.LEAVE_SESSION}`,
            formData,
            {
                headers: { "Content-Type": "multipart/form-data" }
            }
        );
        return response.data;
    },

    getCollaborationSessions: async () => {
        const response = await axios.get(`${config.API_URL}${config.ENDPOINTS.GET_SESSIONS}`);
        return response.data;
    },

    // Project Manager APIs
    
    generateAIProject: async (projectData) => {
        const response = await axios.post(
            `${config.API_URL}/projects/generate-ai-project/`,
            projectData,
            {
                headers: { "Content-Type": "application/json" }
            }
        );
        return response.data;
    },

    createProject: async (projectName, template, description = '') => {
        const formData = new FormData();
        formData.append("project_name", projectName);
        formData.append("template", template);
        formData.append("description", description);
        const response = await axios.post(
            `${config.API_URL}${config.ENDPOINTS.CREATE_PROJECT}`,
            formData,
            {
                headers: { "Content-Type": "multipart/form-data" }
