        );
        return response.data;
    },

    getProjectTemplates: async () => {
        const response = await axios.get(`${config.API_URL}${config.ENDPOINTS.GET_TEMPLATES}`);
        return response.data;
    },

    saveProject: async (projectId, projectData) => {
        const formData = new FormData();
